from flask import Flask, request, redirect, url_for, session, render_template_string

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-in-production'

# Simulated user database
USERS = {
    'admin': 'password123',
    'user1': 'mypassword',
    'demo': 'demo123'
}

# Allowed redirect hosts (to prevent open redirect vulnerabilities)
ALLOWED_HOSTS = {'localhost', '127.0.0.1'}
ALLOWED_PATHS_PREFIX = ['/dashboard', '/profile', '/settings', '/home', '/']


def is_safe_redirect_url(target):
    """Validate that the redirect URL is safe (prevents open redirect attacks)."""
    if not target:
        return False

    from urllib.parse import urlparse, urljoin

    # Parse the target URL
    parsed = urlparse(target)

    # Allow relative URLs (no scheme or netloc)
    if not parsed.scheme and not parsed.netloc:
        # It's a relative URL, check if path is allowed
        return any(target.startswith(prefix) for prefix in ALLOWED_PATHS_PREFIX)

    # For absolute URLs, check if the host is in our allowed list
    if parsed.netloc and parsed.hostname not in ALLOWED_HOSTS:
        return False

    return True


def get_redirect_target():
    """Get the redirect target from the 'next' parameter or referrer."""
    # Check 'next' query parameter first
    target = request.args.get('next') or request.form.get('next')

    if target and is_safe_redirect_url(target):
        return target

    # Fallback to referrer
    referrer = request.referrer
    if referrer and is_safe_redirect_url(referrer):
        return referrer

    return None


def redirect_after_login(default='home'):
    """Redirect user to their intended destination after successful login."""
    target = get_redirect_target()
    if target:
        return redirect(target)
    return redirect(url_for(default))


def login_required(f):
    """Decorator to require login for a route."""
    from functools import wraps

    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            # Store the intended destination and redirect to login
            return redirect(url_for('login', next=request.full_path))
        return f(*args, **kwargs)

    return decorated_function


