# ---------- Routes ----------

@app.route('/')
@login_required
def home():
    return render_template_string(
        PAGE_TEMPLATE,
        title="Home",
        content="Welcome to the home page! You have been successfully authenticated."
    )


@app.route('/login', methods=['GET', 'POST'])
def login():
    if 'username' in session:
        return redirect_after_login()

    error = None
    next_url = request.args.get('next') or request.form.get('next')

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')

        if username in USERS and USERS[username] == password:
            session['username'] = username
            session['logged_in'] = True
            print(f"[LOGIN] User '{username}' authenticated successfully.")

            # Redirect to intended destination
            return redirect_after_login(default='home')
        else:
            error = "Invalid username or password."
            print(f"[LOGIN FAILED] Attempted login for user '{username}'.")

    return render_template_string(LOGIN_TEMPLATE, error=error, next_url=next_url)


@app.route('/logout')
def logout():
    username = session.get('username', 'unknown')
    session.clear()
    print(f"[LOGOUT] User '{username}' logged out.")
    return redirect(url_for('login'))


@app.route('/dashboard')
@login_required
def dashboard():
    return render_template_string(
        PAGE_TEMPLATE,
        title="Dashboard",
        content="This is your personal dashboard with important metrics and data."
    )


@app.route('/profile')
@login_required
def profile():
    return render_template_string(
        PAGE_TEMPLATE,
        title="Profile",
        content=f"This is the profile page for user: {session.get('username')}"
    )


@app.route('/settings')
@login_required
def settings():
    return render_template_string(
        PAGE_TEMPLATE,
        title="Settings",
        content="Manage your account settings and preferences here."
    )


